router.post("/admin/seed", requireAdmin, async (_req, res): Promise<void> => {
  let inserted = 0;
  let skipped = 0;

  for (let i = 0; i < PRODUCTS.length; i++) {
    const p = PRODUCTS[i] as any;
    const existing = await db.select({ slug: productsTable.slug }).from(productsTable).where(eq(productsTable.slug, p.slug));
    if (existing.length > 0) {
      // SKIP — never overwrite admin edits with static seed data.
      // Admin panel changes (heroImage, gallery, price, visibility, etc.)
      // are stored in the DB and would be lost if we UPDATE here.
      skipped++;
    } else {
      await db.insert(productsTable).values({ ...p, sortOrder: i, updatedAt: new Date() });
      inserted++;
    }
  }

  const SITE_CONTENT = [
    { key: "hero_headline", value: "Premium Natural Latex Bedding", type: "text" },
    { key: "hero_subheadline", value: "Sourced from sustainable latex, crafted for comfort", type: "text" },
    { key: "contact_email", value: "hello@xiyora.in", type: "text" },
    { key: "contact_phone", value: "+91 98765 43210", type: "text" },
    { key: "company_tagline", value: "Sleep Naturally. Sleep Better.", type: "text" },
    { key: "whatsapp_number", value: "919876543210", type: "text" },
  ];

  let scInserted = 0;
  for (const item of SITE_CONTENT) {
    const existing = await db.select({ key: siteContentTable.key }).from(siteContentTable).where(eq(siteContentTable.key, item.key));
    if (existing.length === 0) {
      await db.insert(siteContentTable).values({ ...item, updatedAt: new Date() });
      scInserted++;
    }
  }

  res.json({ success: true, products: { inserted, updated: skipped }, siteContent: { inserted: scInserted }, total: PRODUCTS.length });
});

export default router;
